class Solution:
    def findTarget(self, root: Optional[TreeNode], k: int) -> bool:
        vals=[]
        def dfs(n):
            if not n: return
            dfs(n.left); vals.append(n.val); dfs(n.right)
        dfs(root); i,j=0,len(vals)-1
        while i<j:
            s=vals[i]+vals[j]
            if s==k: return True
            if s<k: i+=1
            else: j-=1
        return False

